@app.blob_trigger(arg_name="blob", path="{name}", connection="AzureWebJobsStorage")
def process_blob_file(blob: func.InputStream):
    logging.info("Processing blob: %s, size: %d", blob.name, blob.length if blob.length is not None else -1)
