    blob_name = blob.name.split("/")[-1]
    content = _read_blob_text(container_client, blob_name)
    result = _process_content(blob_name, content)

    _upsert_result(cosmos_container, result)
    _send_event(blob_name, result)

    logging.info("Processed blob successfully: %s", blob_name)
    return


